// ─── CONTACT FORM ─────────────────────────────────────────────────────────────

function ContactForm() {
  const [fields, setFields] = useState({ name: "", email: "", message: "" });
  const [status, setStatus] = useState("");
  const [sending, setSending] = useState(false);

  const send = (e) => {
    e.preventDefault();
    if (!fields.name || !fields.email || !fields.message) {
      setStatus("err:Please fill in all fields.");
      return;
    }
    setSending(true);
    setStatus("");
    // Build mailto link as fallback (no backend needed)
    const subject = encodeURIComponent("Portfolio Contact from " + fields.name);
    const body = encodeURIComponent("Name: " + fields.name + "\nEmail: " + fields.email + "\n\n" + fields.message);
    window.location.href = "mailto:SIDHARTHS4669@GMAIL.COM?subject=" + subject + "&body=" + body;
    setTimeout(() => {
      setSending(false);
      setStatus("ok:Message opened in your mail app!");
      setFields({ name: "", email: "", message: "" });
    }, 1000);
  };

  const isErr = status.startsWith("err:");
  const msg = status.replace(/^(ok|err):/, "");

  return (
    <form className="cf" onSubmit={send} noValidate>
      <div className="cf-field">
        <label className="cf-label">Your Name</label>
        <input className="cf-input" placeholder="e.g. Ravi Kumar" value={fields.name}
          onChange={(e) => setFields((f) => ({ ...f, name: e.target.value }))} />
      </div>
      <div className="cf-field">
        <label className="cf-label">Email Address</label>
        <input className="cf-input" type="email" placeholder="e.g. ravi@gmail.com" value={fields.email}
          onChange={(e) => setFields((f) => ({ ...f, email: e.target.value }))} />
      </div>
      <div className="cf-field">
        <label className="cf-label">Message</label>
        <textarea className="cf-input" rows={5} placeholder="Tell me about your project or opportunity..."
          value={fields.message}
          onChange={(e) => setFields((f) => ({ ...f, message: e.target.value }))} />
      </div>
      {msg && <div className={"cf-status" + (isErr ? " err" : "")}>{msg}</div>}
      <button className="bg" type="submit" style={{width:"100%",padding:"14px",fontSize:12,letterSpacing:3,textAlign:"center"}}>
        {sending ? "OPENING MAIL..." : "SEND MESSAGE"}
      </button>
    </form>
  );
}

