// ─── CERTIFICATES ─────────────────────────────────────────────────────────────

function Certificates({ onBack }) {
  const [certs, setCerts] = useState(() => {
    try { return JSON.parse(localStorage.getItem("ss_certs") || "[]"); } catch { return []; }
  });
  const [profilePic, setProfilePic] = useState(() => localStorage.getItem("ss_profile_pic") || "");
  const [showModal, setShowModal] = useState(false);
  const [viewCert, setViewCert] = useState(null);
  const [form, setForm] = useState({ name: "", issuer: "", date: "", imgData: "" });
  const [preview, setPreview] = useState("");
  const profileRef = useRef(null);

  useEffect(() => { localStorage.setItem("ss_certs", JSON.stringify(certs)); }, [certs]);
  useEffect(() => { localStorage.setItem("ss_profile_pic", profilePic); }, [profilePic]);
  useEffect(() => { window.scrollTo(0, 0); }, []);

  const handleProfilePic = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => setProfilePic(reader.result);
    reader.readAsDataURL(file);
  };

  const handleCertImg = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const isImage = file.type.startsWith("image/");
    if (isImage) {
      const objUrl = URL.createObjectURL(file);
      setPreview(objUrl);
    } else {
      setPreview("__file__:" + file.name);
    }
    const reader = new FileReader();
    reader.onloadend = () => {
      setForm((prev) => ({ ...prev, imgData: reader.result, fileName: file.name, fileType: file.type }));
    };
    reader.readAsDataURL(file);
  };

  const addCert = () => {
    if (!form.name.trim()) return;
    setCerts((prev) => [...prev, { ...form, id: Date.now() }]);
    setForm({ name: "", issuer: "", date: "", imgData: "" });
    setPreview("");
    setShowModal(false);
  };

  const deleteCert = (id) => {
    if (window.confirm("Delete this certificate?")) {
      setCerts((prev) => prev.filter((c) => c.id !== id));
    }
  };

  const closeModal = () => {
    setShowModal(false);
    setForm({ name: "", issuer: "", date: "", imgData: "" });
    setPreview("");
  };

  return (
    <div className="certs-page">
      <div className="certs-hero">
        <button className="certs-back" onClick={onBack}>← BACK TO HOME</button>
        <div className="ey">My Achievements</div>
        <h1 className="certs-title">CERTIFI<br/><span className="ol">CATES</span></h1>
      </div>

      <div className="profile-wrap">
        <div className="profile-pic-box" onClick={() => profileRef.current.click()}>
          {profilePic
            ? <img src={profilePic} alt="Profile"/>
            : <span className="profile-placeholder">SS</span>
          }
          <div className="profile-pic-overlay"><span>Change Photo</span></div>
          <input ref={profileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleProfilePic}/>
        </div>
        <div className="profile-info">
          <h2>Sidharth S.</h2>
          <p>SCMS School of Engineering and Technology, Karukutty</p>
        </div>
      </div>

      <div className="cert-toolbar">
        <div className="cert-toolbar-label">{certs.length} Certificate{certs.length !== 1 ? "s" : ""}</div>
        <button className="cert-add-btn" onClick={() => setShowModal(true)}>+ ADD CERTIFICATE</button>
      </div>

      {certs.length === 0 ? (
        <div className="cert-empty">
          <div className="cert-empty-icon">🎓</div>
          No certificates yet.<br/>
          Click <strong style={{color:"var(--ac)"}}>+ ADD CERTIFICATE</strong> to upload your first one!
        </div>
      ) : (
        <div className="cert-grid">
          {certs.map((c) => (
            <div key={c.id} className="cert-card" onClick={() => setViewCert(c)} style={{cursor:"pointer"}}>
              {c.imgData && c.imgData.startsWith("data:image")
                ? <img src={c.imgData} alt={c.name} className="cert-img"/>
                : <div className="cert-img-placeholder">
                    <span>{c.fileType === "application/pdf" ? "📄" : c.imgData ? "🗂️" : "📜"}</span>
                  </div>
              }
              <div className="cert-body">
                <div className="cert-name">{c.name}</div>
                {c.issuer && <div className="cert-issuer">{c.issuer}</div>}
                {c.date && <div className="cert-date">{c.date}</div>}
              </div>
              <button className="cert-del" onClick={(e) => { e.stopPropagation(); deleteCert(c.id); }}>×</button>
            </div>
          ))}
        </div>
      )}

      {/* VIEWER MODAL */}
      {viewCert && (
        <div className="cert-view-overlay" onClick={(e) => e.target.className === "cert-view-overlay" && setViewCert(null)}>
          <div className="cert-view-header">
            <div>
              <div className="cert-view-title">{viewCert.name}</div>
              {viewCert.issuer && <div className="cert-view-issuer">{viewCert.issuer}{viewCert.date ? ` · ${viewCert.date}` : ""}</div>}
            </div>
            <button className="cert-view-close" onClick={() => setViewCert(null)}>×</button>
          </div>
          <div className="cert-view-body">
            {viewCert.imgData && viewCert.imgData.startsWith("data:image") ? (
              <img src={viewCert.imgData} alt={viewCert.name} className="cert-view-img" />
            ) : viewCert.imgData && viewCert.fileType === "application/pdf" ? (
              <iframe src={viewCert.imgData} className="cert-view-pdf" title={viewCert.name} />
            ) : viewCert.imgData ? (
              <div className="cert-view-file">
                <div className="cert-view-file-icon">🗂️</div>
                <div className="cert-view-file-name">{viewCert.fileName || viewCert.name}</div>
                <a
                  className="bg cert-view-dl"
                  href={viewCert.imgData}
                  download={viewCert.fileName || viewCert.name}
                >
                  DOWNLOAD FILE
                </a>
              </div>
            ) : (
              <div className="cert-view-file">
                <div className="cert-view-file-icon">📜</div>
                <div className="cert-view-file-name">No file attached</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ADD MODAL */}
      {showModal && (
        <div className="modal-bg" onClick={(e) => e.target.className === "modal-bg" && closeModal()}>
          <div className="modal">
            <button className="modal-close" onClick={closeModal}>×</button>
            <h3>Add Certificate</h3>
            <div className="mfield">
              <label>Certificate Name *</label>
              <input
                placeholder="e.g. Machine Learning Specialization"
                value={form.name}
                onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
              />
            </div>
            <div className="mfield">
              <label>Issued By</label>
              <input
                placeholder="e.g. Coursera · Stanford University"
                value={form.issuer}
                onChange={(e) => setForm((f) => ({ ...f, issuer: e.target.value }))}
              />
            </div>
            <div className="mfield">
              <label>Date</label>
              <input
                placeholder="e.g. March 2026"
                value={form.date}
                onChange={(e) => setForm((f) => ({ ...f, date: e.target.value }))}
              />
            </div>
            <div className="mfield">
              <label>Certificate Image</label>
              <div
                className="file-drop"
                onClick={() => document.getElementById("cert-file-input").click()}
              >
                {preview ? "✓ Image selected — click to change" : "Click to upload certificate image"}
              </div>
              <input
                id="cert-file-input"
                type="file"
                accept="*/*"
                style={{display:"none"}}
                onChange={handleCertImg}
              />
              {preview && (
                preview.startsWith("__file__:") ? (
                  <div style={{marginTop:10,padding:"16px 20px",background:"var(--bg)",border:"1px solid var(--b1)",display:"flex",alignItems:"center",gap:12}}>
                    <span style={{fontSize:28}}>📄</span>
                    <div>
                      <div style={{fontSize:13,color:"var(--tx)",fontWeight:500}}>{preview.replace("__file__:","")}</div>
                      <div style={{fontSize:11,color:"var(--ac)",letterSpacing:1,marginTop:2}}>File ready to save</div>
                    </div>
                  </div>
                ) : (
                  <img
                    src={preview}
                    alt="Certificate preview"
                    className="cert-preview-img"
                    style={{display:"block"}}
                  />
                )
              )}
            </div>
            <button className="modal-submit" onClick={addCert}>SAVE CERTIFICATE</button>
          </div>
        </div>
      )}
    </div>
  );
}

